import React, { useMemo, useRef, useState, useEffect } from "react";
import {
  Search,
  ChevronDown,
  ChevronLeft,
  ChevronRight,
  CalendarDays,
  CircleUserRound,
  CircleAlert,
  X,
} from "lucide-react";
import { drivers, loads, weekDays } from "../data/mockData";

const tabs = ["New Load", "Delivered", "En Route"];
const showDayOptions = [7, 8, 9, 10, 14];

const driverFilterOptions = [
  "All",
  "Today's Trucks",
  "Tomorrow's Trucks",
  "Ready Now",
  "Unassigned Loads",
];

const sortOptions = [
  "Driver's Name",
  "Load #",
  "Status",
  "Pickup",
  "Delivery",
];

const filterOptions = ["All", "Active", "Completed", "Pending", "Cancelled"];
const dateOptions = ["This Week", "Last Week", "This Month"];

function cn(...classes) {
  return classes.filter(Boolean).join(" ");
}

function Dropdown({ label, value, options, onChange, width = "w-[170px]" }) {
  const [open, setOpen] = useState(false);
  const ref = useRef(null);

  useEffect(() => {
    function onClickOutside(e) {
      if (ref.current && !ref.current.contains(e.target)) setOpen(false);
    }
    document.addEventListener("mousedown", onClickOutside);
    return () => document.removeEventListener("mousedown", onClickOutside);
  }, []);

  return (
    <div className={cn("relative", width)} ref={ref}>
      <button
        onClick={() => setOpen((s) => !s)}
        className="flex h-10 w-full items-center justify-between rounded-md border border-slate-300 bg-white px-3 text-[13px] text-slate-700 shadow-sm hover:bg-slate-50"
      >
        <span className="truncate">{label ? `${label}: ${value}` : value}</span>
        <ChevronDown className="h-4 w-4 text-slate-500" />
      </button>

      {open && (
        <div className="absolute z-30 mt-1 w-full overflow-hidden rounded-md border border-slate-200 bg-white shadow-lg">
          {options.map((option) => (
            <button
              key={option}
              onClick={() => {
                onChange(option);
                setOpen(false);
              }}
              className={cn(
                "block w-full px-3 py-3 text-left text-[13px] hover:bg-slate-50",
                value === option ? "bg-slate-100 text-slate-900" : "text-slate-700"
              )}
            >
              {option}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

function LoadCard({ load, selected, onClick, multiDay = false }) {
  return (
    <button
      onClick={onClick}
      className={cn(
        "relative z-10 min-h-[74px] rounded-sm border px-2 py-2 text-left transition",
        selected
          ? "border-sky-400 bg-sky-100 shadow-sm"
          : "border-sky-100 bg-sky-50 hover:border-sky-300 hover:bg-sky-100",
        multiDay ? "absolute left-1 top-1" : "w-full"
      )}
      style={
        multiDay
          ? {
              width: `calc(${load.spanDays || 1} * 100% + ${
                ((load.spanDays || 1) - 1) * 1
              }px - 8px)`,
            }
          : undefined
      }
    >
      <div className="text-[13px] font-semibold text-sky-600">#{load.id}</div>
      <div className="mt-1 truncate text-[12px] font-semibold text-slate-800">
        {load.origin}
      </div>
      <div className="truncate text-[12px] text-slate-700">{load.destination}</div>
    </button>
  );
}

function StatusPill({ children, tone = "gray" }) {
  const tones = {
    red: "bg-red-50 text-red-700 border-red-100",
    green: "bg-emerald-50 text-emerald-700 border-emerald-100",
    blue: "bg-sky-50 text-sky-700 border-sky-100",
    gray: "bg-slate-100 text-slate-600 border-slate-200",
    orange: "bg-orange-50 text-orange-700 border-orange-100",
  };

  return (
    <span
      className={cn(
        "inline-flex items-center rounded px-2 py-0.5 text-[11px] font-semibold border",
        tones[tone]
      )}
    >
      {children}
    </span>
  );
}

export default function DispatchBoard() {
  const [activeTab, setActiveTab] = useState("New Load");
  const [search, setSearch] = useState("");
  const [showDays, setShowDays] = useState(7);
  const [selectedLoadId, setSelectedLoadId] = useState(null);

  const [dateFilter, setDateFilter] = useState("This Week");
  const [sortBy, setSortBy] = useState("Driver's Name");
  const [statusFilter, setStatusFilter] = useState("All");
  const [driverFilter, setDriverFilter] = useState("All");

  const visibleDays = useMemo(() => weekDays.slice(0, showDays), [showDays]);

  const filteredLoads = useMemo(() => {
    let result = [...loads];

    if (search.trim()) {
      const q = search.toLowerCase();
      result = result.filter((l) =>
        [
          l.id,
          l.origin,
          l.destination,
          l.status,
          l.miles,
          l.rate,
        ]
          .join(" ")
          .toLowerCase()
          .includes(q)
      );
    }

    if (activeTab === "Delivered") {
      result = result.filter((l) =>
        String(l.status || "").toLowerCase().includes("delivered")
      );
    } else if (activeTab === "En Route") {
      result = result.filter((l) => {
        const s = String(l.status || "").toLowerCase();
        return s.includes("route") || s.includes("picked") || s.includes("transit");
      });
    }

    if (statusFilter !== "All") {
      result = result.filter((l) =>
        String(l.status || "").toLowerCase().includes(statusFilter.toLowerCase())
      );
    }

    if (driverFilter === "Unassigned Loads") {
      result = result.filter((l) => !l.driverId);
    }

    if (sortBy === "Load #") {
      result.sort((a, b) => Number(a.id) - Number(b.id));
    } else if (sortBy === "Status") {
      result.sort((a, b) => String(a.status).localeCompare(String(b.status)));
    } else if (sortBy === "Pickup") {
      result.sort((a, b) => String(a.origin).localeCompare(String(b.origin)));
    } else if (sortBy === "Delivery") {
      result.sort((a, b) =>
        String(a.destination).localeCompare(String(b.destination))
      );
    } else {
      result.sort((a, b) => {
        const da = drivers.find((d) => d.id === a.driverId)?.name || "";
        const db = drivers.find((d) => d.id === b.driverId)?.name || "";
        return da.localeCompare(db);
      });
    }

    return result;
  }, [search, activeTab, statusFilter, driverFilter, sortBy]);

  const selectedLoad =
    filteredLoads.find((item) => item.id === selectedLoadId) || null;

  const getLoadsForDriverDay = (driverId, dayIndex) => {
    return filteredLoads.filter(
      (l) => l.driverId === driverId && l.startDay === dayIndex
    );
  };

  const unassignedLoads = filteredLoads.filter((l) => !l.driverId);

  return (
    <div className="flex h-full flex-col bg-[#f5f6f7]">
      {/* Header */}
      <div className="border-b border-slate-300 bg-[#f3f3f3] px-7 py-3">
        <div className="flex flex-wrap items-center justify-between gap-4">
          <h1 className="text-[20px] font-bold text-slate-800">Dispatch Board</h1>

          <div className="flex flex-wrap items-center gap-2">
            <Dropdown
              value={dateFilter}
              label="Search by Date"
              options={dateOptions}
              onChange={setDateFilter}
              width="w-[150px]"
            />
            <Dropdown
              value={sortBy}
              label="Sort by"
              options={sortOptions}
              onChange={setSortBy}
              width="w-[170px]"
            />
            <Dropdown
              value={statusFilter}
              label="Filter by"
              options={filterOptions}
              onChange={setStatusFilter}
              width="w-[140px]"
            />
            <Dropdown
              value={driverFilter}
              label="Drivers"
              options={driverFilterOptions}
              onChange={setDriverFilter}
              width="w-[160px]"
            />

            <div className="ml-4 flex items-center gap-2">
              {tabs.map((tab) => (
                <button
                  key={tab}
                  onClick={() => setActiveTab(tab)}
                  className={cn(
                    "h-9 rounded-full border px-5 text-[13px] font-medium transition",
                    tab === "Delivered"
                      ? activeTab === tab
                        ? "border-orange-300 bg-orange-50 text-orange-600"
                        : "border-orange-300 bg-white text-orange-500"
                      : tab === "En Route"
                      ? activeTab === tab
                        ? "border-sky-300 bg-sky-50 text-sky-600"
                        : "border-sky-300 bg-white text-sky-500"
                      : activeTab === tab
                      ? "border-slate-400 bg-slate-100 text-slate-700"
                      : "border-slate-300 bg-white text-slate-500"
                  )}
                >
                  {tab}
                </button>
              ))}
            </div>

            <div className="ml-2 flex items-center rounded-md border border-slate-300 bg-white px-3">
              <Search className="h-4 w-4 text-slate-400" />
              <input
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                placeholder="Search"
                className="h-10 w-[130px] border-none bg-transparent px-2 text-[13px] outline-none"
              />
            </div>

            <button className="flex h-10 w-10 items-center justify-center rounded-md border border-slate-300 bg-white text-slate-500 hover:bg-slate-50">
              <CalendarDays className="h-4 w-4" />
            </button>
          </div>
        </div>
      </div>

      {/* Board Header Dates */}
      <div className="border-b border-slate-300 bg-[#eaf5ea]">
        <div className="grid grid-cols-[270px_repeat(7,minmax(140px,1fr))_240px]">
          <div className="flex items-center gap-2 border-r border-slate-300 px-6 py-3 text-[14px] font-semibold text-emerald-600">
            <ChevronLeft className="h-4 w-4" />
            <ChevronLeft className="-ml-2 h-4 w-4" />
            <span>Mar 30 - Apr 5, 2026</span>
            <ChevronRight className="h-4 w-4" />
            <ChevronRight className="-ml-2 h-4 w-4" />
          </div>

          {visibleDays.slice(0, 7).map((day) => (
            <div
              key={`${day.label}-${day.date}`}
              className="flex items-center justify-center border-r border-slate-300 px-2 py-3 text-[13px] font-bold text-slate-500"
            >
              {day.label} {day.date}
            </div>
          ))}

          <div className="flex items-center justify-between bg-[#f6f3e8] px-4 py-3 text-[13px] font-bold text-slate-500">
            <span>NOTES</span>
            <X className="h-4 w-4 cursor-pointer text-slate-600" />
          </div>
        </div>
      </div>

      {/* Board Body */}
      <div className="flex-1 overflow-auto">
        <div className="grid min-h-[620px] grid-cols-[270px_repeat(7,minmax(140px,1fr))_240px]">
          {/* Driver rows */}
          <div className="contents">
            {/* Assigned Driver */}
            <div className="border-r border-b border-slate-300 bg-white px-3 py-2">
              <div className="flex items-start justify-between">
                <div className="flex gap-3">
                  <div className="mt-1 flex h-11 w-11 items-center justify-center rounded-full bg-emerald-100 text-emerald-500">
                    <CircleUserRound className="h-6 w-6" />
                  </div>
                  <div>
                    <div className="text-[15px] font-bold text-slate-800">
                      Xumotyun Baxriddinov [Drv]
                    </div>
                    <div className="text-[14px] text-slate-700">(930) 077-7061</div>
                  </div>
                </div>

                <div className="mt-1 flex h-5 w-5 items-center justify-center rounded border border-slate-300 text-slate-400">
                  <CircleAlert className="h-3 w-3" />
                </div>
              </div>
            </div>

            {visibleDays.slice(0, 7).map((day, idx) => {
              const dayLoads = getLoadsForDriverDay(1, idx);
              return (
                <div
                  key={`driver1-${idx}`}
                  className="relative border-r border-b border-slate-300 bg-[#f7fafc]"
                >
                  {dayLoads.length > 0 ? (
                    dayLoads.map((load) => (
                      <LoadCard
                        key={load.id}
                        load={load}
                        selected={selectedLoadId === load.id}
                        onClick={() =>
                          setSelectedLoadId((prev) =>
                            prev === load.id ? null : load.id
                          )
                        }
                        multiDay={(load.spanDays || 1) > 1}
                      />
                    ))
                  ) : (
                    <div className="px-2 py-16 text-[14px] text-slate-300">
                      {idx < 2 ? "INACTIVE" : ""}
                    </div>
                  )}
                </div>
              );
            })}

            <div className="border-b border-slate-300 bg-[#f6f3e8] px-4 py-3">
              <div className="flex items-center gap-3 text-[12px] font-semibold text-sky-500">
                <button>⊕ Add note</button>
                <button>⊕ Add lumper</button>
                <button>⌘ View details</button>
              </div>
              <div className="mt-2 text-[18px] text-slate-700">INACTIVE</div>
            </div>

            {/* Unassigned row */}
            <div className="border-r border-b border-slate-300 bg-white px-3 py-2">
              <div className="flex items-start justify-between">
                <div className="flex gap-3">
                  <div className="mt-1 flex h-11 w-11 items-center justify-center rounded-full bg-emerald-100 text-emerald-500">
                    <CircleUserRound className="h-6 w-6" />
                  </div>
                  <div>
                    <div className="text-[15px] font-bold text-slate-800">
                      Unassigned loads
                    </div>
                  </div>
                </div>

                <div className="mt-1 flex h-5 w-5 items-center justify-center rounded border border-slate-300 text-slate-400">
                  <CircleAlert className="h-3 w-3" />
                </div>
              </div>
            </div>

            {visibleDays.slice(0, 7).map((_, idx) => {
              const dayLoads = unassignedLoads.filter((l) => l.startDay === idx);
              return (
                <div
                  key={`unassigned-${idx}`}
                  className="relative border-r border-b border-slate-300 bg-[#f7fafc]"
                >
                  {dayLoads.map((load) => (
                    <LoadCard
                      key={load.id}
                      load={load}
                      selected={selectedLoadId === load.id}
                      onClick={() =>
                        setSelectedLoadId((prev) => (prev === load.id ? null : load.id))
                      }
                    />
                  ))}
                </div>
              );
            })}

            <div className="border-b border-slate-300 bg-[#f6f3e8]" />
          </div>
        </div>
      </div>

      {/* Bottom */}
      <div className="flex items-center justify-end gap-5 border-t border-slate-300 bg-[#f5f5f5] px-6 py-3">
        <div className="text-[14px] font-semibold text-slate-700">Show days</div>
        <div className="flex items-center gap-5">
          {showDayOptions.map((n) => (
            <button
              key={n}
              onClick={() => setShowDays(n)}
              className={cn(
                "text-[15px] font-semibold",
                showDays === n ? "text-sky-600" : "text-slate-500 hover:text-slate-700"
              )}
            >
              {n}
            </button>
          ))}
        </div>
      </div>

      {/* Optional selected load floating detail */}
      {selectedLoad && (
        <div className="fixed bottom-6 right-6 z-40 w-[260px] rounded-lg border border-slate-200 bg-white p-4 shadow-xl">
          <div className="mb-2 text-[15px] font-bold text-sky-600">
            #{selectedLoad.id}
          </div>
          <div className="space-y-1 text-[13px] text-slate-700">
            <div>
              <span className="font-semibold">Origin:</span> {selectedLoad.origin}
            </div>
            <div>
              <span className="font-semibold">Destination:</span>{" "}
              {selectedLoad.destination}
            </div>
            <div>
              <span className="font-semibold">Miles:</span> {selectedLoad.miles}
            </div>
            <div>
              <span className="font-semibold">Rate:</span> ${selectedLoad.rate}
            </div>
          </div>

          <div className="mt-3">
            <StatusPill tone="blue">{selectedLoad.status || "Pending"}</StatusPill>
          </div>
        </div>
      )}
    </div>
  );
}
